#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

#define ROWS 4096
#define COLS 4096

int matrix[ROWS][COLS];

void cache_friendly_traversal() {
    // Row-Major: The innermost loop MUST iterate the Columns.
    // The CPU prefetcher pulls the next 16 integers into L1 cache for free.
    for (size_t r = 0; r < ROWS; r++) {
        for (size_t c = 0; c < COLS; c++) {
            matrix[r][c] = 1;
        }
    }
}

void cache_hostile_traversal() {
    // Column-Major: The innermost loop iterates the Rows.
    // Jumps 16,384 bytes on every step. 100% Cache Miss rate. Destroys performance.
    for (size_t c = 0; c < COLS; c++) {
        for (size_t r = 0; r < ROWS; r++) {
            matrix[r][c] = 0;
        }
    }
}

